  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { Layer, Shape } from 'react-konva';
  3→
  4→const TWO_PI = Math.PI * 2;
  5→const SPEED_LINE_COUNT = 30;
  6→
  7→const RocketLayer = React.memo(({ rocketMode }) => {
  8→    const {
  9→        layerRef, starsRef, sortedIndicesRef, velocity, targetIndexRef,
 10→        stageSizeRef, project, getSpeedRatio,
 11→    } = rocketMode;
 12→
 13→    const shapeRef = useRef(null);
 14→    const timeRef = useRef(0);
 15→
 16→    // Attach the Konva Layer ref so the hook can call batchDraw
 17→    const layerCallbackRef = useCallback((node) => {
 18→        layerRef.current = node;
 19→    }, [layerRef]);
 20→
 21→    // Keep time ticking for pulsing effects
 22→    useEffect(() => {
 23→        const update = () => {
 24→            timeRef.current = performance.now();
 25→        };
 26→        const id = setInterval(update, 16);
 27→        return () => clearInterval(id);
 28→    }, []);
 29→
 30→    return (
 31→        <Layer ref={layerCallbackRef} listening={false}>
 32→            <Shape
 33→                ref={shapeRef}
 34→                sceneFunc={(ctx) => {
 35→                    const size = stageSizeRef.current;
 36→                    const cx = size.width / 2;
 37→                    const cy = size.height / 2;
 38→                    const stars = starsRef.current;
 39→                    const sorted = sortedIndicesRef.current;
 40→                    const speedRatio = getSpeedRatio();
 41→                    const time = timeRef.current || performance.now();
 42→                    const targetIdx = targetIndexRef.current;
 43→                    const bufferX = size.width / 2 + 200;
 44→                    const bufferY = size.height / 2 + 200;
 45→
 46→                    // ── 1. Speed lines (behind stars) ──────────────────
 47→                    if (speedRatio > 0.4) {
 48→                        const lineAlpha = (speedRatio - 0.4) / 0.6;
 49→                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
 50→                        ctx.lineWidth = 1;
 51→
 52→                        for (let i = 0; i < SPEED_LINE_COUNT; i++) {
 53→                            const angle = (i / SPEED_LINE_COUNT) * TWO_PI;
 54→                            const innerR = 80 + Math.sin(time * 0.002 + i) * 20;
 55→                            const outerR = innerR + 60 + speedRatio * 200;
 56→                            ctx.beginPath();
 57→                            ctx.moveTo(
 58→                                cx + Math.cos(angle) * innerR,
 59→                                cy + Math.sin(angle) * innerR
 60→                            );
 61→                            ctx.lineTo(
 62→                                cx + Math.cos(angle) * outerR,
 63→                                cy + Math.sin(angle) * outerR
 64→                            );
 65→                            ctx.stroke();
 66→                        }
 67→                    }
 68→
 69→                    // ── 2. Stars (painter's algorithm, far first) ──────
 70→                    for (let si = 0; si < sorted.length; si++) {
 71→                        const idx = sorted[si];
 72→                        const star = stars[idx];
 73→                        const { projX, projY, scale } = project(star, cx, cy);
