.universeContainer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(ellipse at center, #0a0e1a 0%, #000000 100%);
    touch-action: none;
    cursor: grab;
    z-index: 1000;
    overflow: hidden;
}

.universeContainer.grabbing {
    cursor: grabbing;
}

.backButton {
    position: absolute;
    top: 16px;
    left: 16px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.backButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.backButton svg {
    width: 18px;
    height: 18px;
    fill: #e0e0e0;
}

.distanceTracker {
    position: absolute;
    bottom: 184px;
    left: 16px;
    z-index: 1010;
    padding: 6px 12px;
    background: rgba(255, 255, 255, 0.04);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.06);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.35);
    font-size: 12px;
    font-family: monospace;
    pointer-events: none;
}

.loadingOverlay {
    position: absolute;
    inset: 0;
    z-index: 1040;
    display: flex;
    align-items: center;
    justify-content: center;
    background: radial-gradient(ellipse at center, rgba(10, 14, 26, 0.55) 0%, rgba(0, 0, 0, 0.72) 100%);
}

.loadingCard {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
    padding: 18px 22px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border: 1px solid rgba(255, 255, 255, 0.14);
    border-radius: 14px;
}

.loadingSpinner {
    width: 26px;
    height: 26px;
    border-radius: 50%;
    border: 2px solid rgba(255, 255, 255, 0.15);
    border-top-color: rgba(95, 146, 255, 0.95);
    animation: universeSpin 0.8s linear infinite;
}

.loadingText {
    font-size: 12px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.82);
    letter-spacing: 0.02em;
}

@keyframes universeSpin {
    from {
        transform: rotate(0deg);
    }
    to {
        transform: rotate(360deg);
    }
}

.previewPanel {
    position: absolute;
    bottom: 16px;
    right: 16px;
    z-index: 1010;
    width: 320px;
    max-height: 340px;
    overflow-y: auto;
    padding: 20px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    color: #e0e0e0;
}

.previewClose {
    position: absolute;
    top: 10px;
    right: 10px;
    z-index: 1;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: rgba(255, 255, 255, 0.7);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
    padding: 0;
    font-family: inherit;
}

.previewClose:hover {
    background: rgba(0, 0, 0, 0.6);
    color: #fff;
}

.previewAuthor {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 12px;
}

.previewAvatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid rgba(255, 255, 255, 0.15);
}

.previewAuthorName {
    font-size: 13px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
}

.previewTitle {
    font-size: 16px;
    font-weight: 700;
    margin-bottom: 8px;
    color: #ffffff;
    line-height: 1.3;
}

.previewSnippet {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.55);
    margin-bottom: 16px;
    display: -webkit-box;
    -webkit-line-clamp: 4;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.previewLikes {
    font-size: 11px;
    color: rgba(255, 255, 255, 0.35);
    margin-bottom: 14px;
}

.previewReadBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.previewReadBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.previewActions {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.wormholeBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.wormholeBtnWrap {
    position: relative;
}

.wormholeBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.wormholeTooltip {
    position: absolute;
    bottom: calc(100% + 8px);
    left: 50%;
    transform: translateX(-50%);
    width: 220px;
    padding: 8px 12px;
    background: rgba(10, 14, 26, 0.92);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    border: 1px solid rgba(95, 146, 255, 0.25);
    border-radius: 10px;
    color: rgba(255, 255, 255, 0.8);
    font-size: 11px;
    line-height: 1.45;
    text-align: center;
    pointer-events: none;
    opacity: 0;
    transition: opacity 0.2s;
}

.wormholeTooltip::after {
    content: '';
    position: absolute;
    top: 100%;
    left: 50%;
    transform: translateX(-50%);
    border: 5px solid transparent;
    border-top-color: rgba(95, 146, 255, 0.25);
}

.wormholeBtnWrap:hover .wormholeTooltip {
    opacity: 1;
}

/* Galaxy preview panel */
.galaxyPreviewPanel {
    position: absolute;
    bottom: 16px;
    right: 16px;
    z-index: 1010;
    width: 320px;
    max-height: 400px;
    overflow: hidden;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 16px;
    color: #e0e0e0;
}

.galaxyPreviewClose {
    position: absolute;
    top: 8px;
    right: 8px;
    z-index: 1;
    width: 28px;
    height: 28px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: rgba(0, 0, 0, 0.4);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 50%;
    color: rgba(255, 255, 255, 0.7);
    font-size: 16px;
    line-height: 1;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
    padding: 0;
    font-family: inherit;
}

.galaxyPreviewClose:hover {
    background: rgba(0, 0, 0, 0.6);
    color: #fff;
}

.galaxyPreviewBg {
    height: 120px;
    border-radius: 16px 16px 0 0;
    background-size: cover;
    background-position: center;
    background-color: rgba(95, 146, 255, 0.12);
}

.galaxyPreviewContent {
    padding: 0 20px 20px;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.galaxyPreviewAvatar {
    width: 56px;
    height: 56px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid rgba(255, 255, 255, 0.15);
    margin-top: -28px;
    background: #0a0e1a;
}

.galaxyPreviewHeading {
    font-size: 15px;
    font-weight: 600;
    color: rgba(255, 255, 255, 0.85);
    margin-top: 10px;
    text-align: center;
}

.galaxyPreviewBio {
    font-size: 13px;
    line-height: 1.5;
    color: rgba(255, 255, 255, 0.5);
    margin-top: 8px;
    text-align: center;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.galaxyPreviewVisitBtn {
    display: inline-block;
    margin-top: 16px;
    padding: 8px 22px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewVisitBtn:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

/* Minimap */
.minimap {
    position: absolute;
    bottom: 16px;
    left: 16px;
    z-index: 1010;
    width: 160px;
    height: 160px;
    border-radius: 10px;
    cursor: crosshair;
    pointer-events: auto;
    transition: opacity 0.2s;
}

.minimap:hover {
    opacity: 0.95;
}

/* Link Mode UI */
.linkModeButton {
    position: absolute;
    top: 16px;
    left: 130px;
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 13px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s, box-shadow 0.2s;
}

.linkModeButton:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.linkModeButton svg {
    flex-shrink: 0;
}

.linkModeActive {
    background: rgba(95, 146, 255, 0.12);
    border-color: rgba(95, 146, 255, 0.5);
    color: #5f92ff;
    box-shadow: 0 0 16px rgba(95, 146, 255, 0.2), inset 0 0 8px rgba(95, 146, 255, 0.08);
}

.linkModeActive:hover {
    background: rgba(95, 146, 255, 0.18);
    border-color: rgba(95, 146, 255, 0.6);
}

.linkModeIndicator {
    position: absolute;
    top: 66px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1010;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 10px 20px;
    background: rgba(10, 14, 26, 0.85);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(95, 146, 255, 0.3);
    border-radius: 12px;
    color: rgba(255, 255, 255, 0.8);
    font-size: 13px;
    white-space: nowrap;
}

.linkModeCancel {
    padding: 4px 12px;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.15);
    border-radius: 8px;
    color: rgba(255, 255, 255, 0.6);
    font-size: 12px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}

.linkModeCancel:hover {
    background: rgba(255, 255, 255, 0.15);
    color: #fff;
}

/* Label input panel for constellation naming */
.labelInputPanel {
    position: absolute;
    top: 66px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1010;
    display: flex;
    flex-direction: column;
    gap: 10px;
    padding: 16px 20px;
    background: rgba(10, 14, 26, 0.88);
    backdrop-filter: blur(14px);
    -webkit-backdrop-filter: blur(14px);
    border: 1px solid rgba(95, 146, 255, 0.3);
    border-radius: 14px;
    min-width: 280px;
    max-width: 380px;
}

.labelInputHeader {
    font-size: 13px;
    color: rgba(255, 255, 255, 0.75);
    text-align: center;
    line-height: 1.4;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.labelInputField {
    width: 100%;
    padding: 8px 0;
    background: transparent;
    border: none;
    border-bottom: 1px solid rgba(255, 255, 255, 0.15);
    color: #fff;
    font-size: 14px;
    font-family: inherit;
    outline: none;
    transition: border-color 0.2s;
    box-sizing: border-box;
}

.labelInputField::placeholder {
    color: rgba(255, 255, 255, 0.3);
}

.labelInputField:focus {
    border-bottom-color: rgba(95, 146, 255, 0.5);
}

.labelInputActions {
    display: flex;
    gap: 8px;
    justify-content: flex-end;
}

.labelInputCreate {
    padding: 7px 18px;
    background: rgba(95, 146, 255, 0.15);
    border: 1px solid rgba(95, 146, 255, 0.4);
    border-radius: 10px;
    color: #5f92ff;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.labelInputCreate:hover {
    background: rgba(95, 146, 255, 0.25);
    border-color: rgba(95, 146, 255, 0.6);
}

.labelInputCreate:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

.labelInputCancel {
    padding: 7px 14px;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 10px;
    color: rgba(255, 255, 255, 0.5);
    font-size: 13px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, color 0.2s;
}

.labelInputCancel:hover {
    background: rgba(255, 255, 255, 0.12);
    color: rgba(255, 255, 255, 0.8);
}

/* Constellation travel button */
.constellationBtn {
    display: inline-block;
    padding: 8px 22px;
    background: rgba(176, 95, 255, 0.12);
    border: 1px solid rgba(176, 95, 255, 0.35);
    border-radius: 10px;
    color: #b05fff;
    font-size: 12px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: 100%;
}

.constellationBtn:hover {
    background: rgba(176, 95, 255, 0.22);
    border-color: rgba(176, 95, 255, 0.55);
}

/* Wormhole warp overlay */
.warpOverlay {
    position: absolute;
    inset: 0;
    z-index: 10;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        transparent 20%,
        rgba(95, 146, 255, 0.15) 60%,
        rgba(0, 0, 0, 0.6) 100%
    );
    animation: warpPulse 1.8s ease-in-out forwards;
}

@keyframes warpPulse {
    0%   { opacity: 0; }
    15%  { opacity: 1; }
    85%  { opacity: 1; }
    100% { opacity: 0; }
}

@media (max-width: 600px) {
    .previewPanel {
        width: auto;
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 260px;
        box-sizing: border-box;
    }

    .backButton {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .distanceTracker {
        bottom: auto;
        top: 52px;
        right: 12px;
        left: auto;
    }

    .minimap {
        width: 100px;
        height: 100px;
        bottom: 12px;
        left: 12px;
    }

    .galaxyPreviewPanel {
        width: calc(100% - 32px);
        right: 16px;
        left: 16px;
        bottom: 12px;
        max-height: 300px;
    }

    .linkModeButton {
        top: 12px;
        left: auto;
        right: 12px;
        padding: 8px 14px;
        font-size: 12px;
    }

    .linkModeIndicator {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        white-space: normal;
        font-size: 12px;
    }

    .labelInputPanel {
        top: 56px;
        left: 12px;
        right: 12px;
        transform: none;
        min-width: 0;
        max-width: none;
    }

    .labelInputHeader {
        white-space: normal;
        font-size: 12px;
    }

    .rocketSpeedBar {
        width: 120px;
    }

    .rocketControls {
        display: none;
    }

    .rocketExitBtn {
        top: 12px;
        left: 12px;
        padding: 8px 14px;
        font-size: 13px;
    }

    .rocketTarget {
        bottom: 120px;
    }
}

/* ── Rocket Mode ───────────────────────────────────────────────── */

.rocketHud {
    position: absolute;
    inset: 0;
    z-index: 1020;
    pointer-events: none;
}

.rocketExitBtn {
    position: absolute;
    top: 16px;
    left: 16px;
    pointer-events: auto;
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    color: #e0e0e0;
    font-size: 14px;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.rocketExitBtn:hover {
    background: rgba(255, 255, 255, 0.12);
    border-color: rgba(255, 255, 255, 0.2);
}

.rocketSpeedBar {
    position: absolute;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px 18px;
    background: rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    pointer-events: none;
}

.rocketSpeedLabel {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.4);
    letter-spacing: 0.05em;
}

.rocketSpeedTrack {
    width: 160px;
    height: 6px;
    background: rgba(255, 255, 255, 0.08);
    border-radius: 3px;
    overflow: hidden;
}

.rocketSpeedFill {
    height: 100%;
    background: linear-gradient(90deg, #5f92ff, #ff5fa2);
    border-radius: 3px;
    transition: width 0.1s linear;
}

.rocketSpeedValue {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.5);
    min-width: 32px;
    text-align: right;
}

.rocketTarget {
    position: absolute;
    bottom: 80px;
    left: 50%;
    transform: translateX(-50%);
    text-align: center;
    pointer-events: none;
}

.rocketTargetTitle {
    font-size: 15px;
    font-weight: 700;
    color: rgba(255, 255, 255, 0.9);
    text-shadow: 0 0 12px rgba(0, 255, 255, 0.3);
    margin-bottom: 2px;
    white-space: nowrap;
    max-width: 320px;
    overflow: hidden;
    text-overflow: ellipsis;
}

.rocketTargetAuthor {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.45);
    margin-bottom: 6px;
}

.rocketTargetPrompt {
    font-size: 12px;
    font-family: monospace;
    color: rgba(0, 255, 255, 0.7);
    animation: rocketPromptPulse 1.5s ease-in-out infinite;
}

.rocketControls {
    position: absolute;
    bottom: 24px;
    right: 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
    pointer-events: none;
}

.rocketControls span {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.25);
}

.galaxyPreviewExploreBtn {
    display: inline-block;
    margin-top: 8px;
    padding: 8px 22px;
    background: rgba(255, 160, 50, 0.15);
    border: 1px solid rgba(255, 160, 50, 0.4);
    border-radius: 10px;
    color: #ffa032;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewExploreBtn:hover {
    background: rgba(255, 160, 50, 0.25);
    border-color: rgba(255, 160, 50, 0.6);
}

.rocketWarpIn {
    position: absolute;
    inset: 0;
    z-index: 1030;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        rgba(95, 146, 255, 0.35) 0%,
        rgba(0, 0, 0, 0.9) 70%,
        rgba(0, 0, 0, 1) 100%
    );
    animation: rocketWarpInAnim 1s ease-out forwards;
}

@keyframes rocketWarpInAnim {
    0% {
        opacity: 0;
        transform: scale(1);
    }
    40% {
        opacity: 1;
    }
    100% {
        opacity: 0;
        transform: scale(3);
    }
}

@keyframes rocketPromptPulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}

