import { useRef, useCallback } from 'react';
import { getStarColor, getStarRadius, simpleHash } from '../utils/starUtils';

// ── Constants ──────────────────────────────────────────────────────────
const MAX_SPEED = 12;
const ACCEL = 0.25;
const BRAKE = 0.15;
const FRICTION = 0.985;
const TURN_RATE = 0.035;
const MIN_Z = 0.5;
const MAX_Z = 800;
const SPAWN_Z_RANGE = 400;
const SORT_INTERVAL = 5;
const TARGET_DIST_MAX = 150;
const TARGET_Z_MIN = 2;
const TWO_PI = Math.PI * 2;

/** Parse "#5f92ff" → { r, g, b } */
const parseHex = (hex) => ({
    r: parseInt(hex.slice(1, 3), 16),
    g: parseInt(hex.slice(3, 5), 16),
    b: parseInt(hex.slice(5, 7), 16),
});

/** Seeded pseudo-random from integer seed */
const seededRandom = (seed) => {
    let s = seed | 0;
    return () => {
        s = (s * 1664525 + 1013904223) | 0;
        return ((s >>> 0) / 4294967296);
    };
};

const useRocketMode = () => {
    const isActiveRef = useRef(false);
    const rocketPosRef = useRef({ x: 0, y: 0 });
    const headingRef = useRef(-Math.PI / 2);
    const velocityRef = useRef(0);
    const starsRef = useRef([]);
    const sortedIndicesRef = useRef([]);
    const keysRef = useRef({ w: false, s: false, a: false, d: false });
    const targetIndexRef = useRef(-1);
    const frameRef = useRef(0);
    const layerRef = useRef(null);
    const rafRef = useRef(null);
    const stageSizeRef = useRef({ width: 0, height: 0 });

    const sortStars = useCallback(() => {
        const stars = starsRef.current;
        const indices = sortedIndicesRef.current;
        // Simple insertion sort — fast for nearly-sorted arrays
        for (let i = 1; i < indices.length; i++) {
            const key = indices[i];
            let j = i - 1;
            while (j >= 0 && stars[indices[j]].z < stars[key].z) {
                indices[j + 1] = indices[j];
                j--;
            }
            indices[j + 1] = key;
        }
    }, []);

    const tick = useCallback(() => {
        if (!isActiveRef.current) return;

        const keys = keysRef.current;
        const pos = rocketPosRef.current;
        const stars = starsRef.current;
        const size = stageSizeRef.current;

        // ── Heading ────────────────────────────────────────────────
        if (keys.a) headingRef.current -= TURN_RATE;
        if (keys.d) headingRef.current += TURN_RATE;

        // ── Velocity ───────────────────────────────────────────────
        if (keys.w) {
            velocityRef.current = Math.min(velocityRef.current + ACCEL, MAX_SPEED);
        } else if (keys.s) {
            velocityRef.current = Math.max(velocityRef.current - BRAKE, 0);
        } else {
            velocityRef.current *= FRICTION;
            if (velocityRef.current < 0.01) velocityRef.current = 0;
        }

        const heading = headingRef.current;
        const velocity = velocityRef.current;

        // ── Position ───────────────────────────────────────────────
        pos.x += Math.cos(heading) * velocity;
        pos.y += Math.sin(heading) * velocity;

        // ── Z update + recycle ─────────────────────────────────────
        const zStep = velocity * 0.5;
        for (let i = 0; i < stars.length; i++) {
            const star = stars[i];
            star.z -= zStep;
            if (star.z < MIN_Z) {
                star.z = MAX_Z - Math.random() * SPAWN_Z_RANGE;
                star.worldX = pos.x + (Math.random() - 0.5) * 4000;
                star.worldY = pos.y + (Math.random() - 0.5) * 4000;
            }
        }

        // ── Sort (every N frames) ─────────────────────────────────
        frameRef.current++;
        if (frameRef.current % SORT_INTERVAL === 0) {
            sortStars();
        }

