                colorRgb: parseHex(color),
                radius: getStarRadius(likeCount),
                title: post.title || 'Untitled',
                authorName: post.users?.name || post.user_name || 'Anonymous',
                post,
            });
        }

        starsRef.current = stars;

        // Build sorted indices (far → near)
        const indices = new Array(stars.length);
        for (let i = 0; i < stars.length; i++) indices[i] = i;
        indices.sort((a, b) => stars[b].z - stars[a].z);
        sortedIndicesRef.current = indices;

        // Key listeners
        const onKeyDown = (e) => {
            const key = e.key.toLowerCase();
            if (key === 'w' || key === 'arrowup') keysRef.current.w = true;
            if (key === 's' || key === 'arrowdown') keysRef.current.s = true;
            if (key === 'a' || key === 'arrowleft') keysRef.current.a = true;
            if (key === 'd' || key === 'arrowright') keysRef.current.d = true;
        };
        const onKeyUp = (e) => {
            const key = e.key.toLowerCase();
            if (key === 'w' || key === 'arrowup') keysRef.current.w = false;
            if (key === 's' || key === 'arrowdown') keysRef.current.s = false;
            if (key === 'a' || key === 'arrowleft') keysRef.current.a = false;
            if (key === 'd' || key === 'arrowright') keysRef.current.d = false;
        };

        window.addEventListener('keydown', onKeyDown);
        window.addEventListener('keyup', onKeyUp);

        // Store cleanup refs
        keysRef.current = { w: false, s: false, a: false, d: false };
        isActiveRef.current = true;

        // Store listener refs for cleanup
        rocketPosRef.current._onKeyDown = onKeyDown;
        rocketPosRef.current._onKeyUp = onKeyUp;

        // Start rAF
        rafRef.current = requestAnimationFrame(tick);
    }, [tick]);

    const exit = useCallback(() => {
        isActiveRef.current = false;
        if (rafRef.current) {
            cancelAnimationFrame(rafRef.current);
            rafRef.current = null;
        }
        // Remove key listeners
        const pos = rocketPosRef.current;
        if (pos._onKeyDown) {
            window.removeEventListener('keydown', pos._onKeyDown);
            window.removeEventListener('keyup', pos._onKeyUp);
            delete pos._onKeyDown;
            delete pos._onKeyUp;
        }
        keysRef.current = { w: false, s: false, a: false, d: false };
    }, []);

    const project = useCallback((star, cx, cy) => {
        const pos = rocketPosRef.current;
        const heading = headingRef.current;
        const relX = star.worldX - pos.x;
        const relY = star.worldY - pos.y;
        const cosH = Math.cos(-heading + Math.PI / 2);
        const sinH = Math.sin(-heading + Math.PI / 2);
        const rotX = relX * cosH - relY * sinH;
        const rotY = relX * sinH + relY * cosH;
