                                ctx.font = `${authorSize}px sans-serif`;
                                ctx.fillStyle = `rgba(140,180,255,${labelOpacity * 0.7})`;
                                ctx.fillText(star.authorName, projX, labelY + authorSize + 2);
                            }
                        }

