    margin-bottom: 2px;
    white-space: nowrap;
    max-width: 320px;
    overflow: hidden;
    text-overflow: ellipsis;
}

.rocketTargetAuthor {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.45);
    margin-bottom: 6px;
}

.rocketTargetPrompt {
    font-size: 12px;
    font-family: monospace;
    color: rgba(0, 255, 255, 0.7);
    animation: rocketPromptPulse 1.5s ease-in-out infinite;
}

.rocketControls {
    position: absolute;
    bottom: 24px;
    right: 16px;
    display: flex;
    flex-direction: column;
    gap: 4px;
    pointer-events: none;
}

.rocketControls span {
    font-size: 11px;
    font-family: monospace;
    color: rgba(255, 255, 255, 0.25);
}

.galaxyPreviewExploreBtn {
    display: inline-block;
    margin-top: 8px;
    padding: 8px 22px;
    background: rgba(255, 160, 50, 0.15);
    border: 1px solid rgba(255, 160, 50, 0.4);
    border-radius: 10px;
    color: #ffa032;
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    cursor: pointer;
    transition: background 0.2s, border-color 0.2s;
}

.galaxyPreviewExploreBtn:hover {
    background: rgba(255, 160, 50, 0.25);
    border-color: rgba(255, 160, 50, 0.6);
}

.rocketWarpIn {
    position: absolute;
    inset: 0;
    z-index: 1030;
    pointer-events: none;
    background: radial-gradient(
        ellipse at center,
        rgba(95, 146, 255, 0.35) 0%,
        rgba(0, 0, 0, 0.9) 70%,
        rgba(0, 0, 0, 1) 100%
    );
    animation: rocketWarpInAnim 1s ease-out forwards;
}

@keyframes rocketWarpInAnim {
    0% {
        opacity: 0;
        transform: scale(1);
    }
    40% {
        opacity: 1;
    }
    100% {
        opacity: 0;
        transform: scale(3);
    }
}

@keyframes rocketPromptPulse {
    0%, 100% {
        opacity: 0.5;
    }
    50% {
        opacity: 1;
    }
}

