import { chromium } from 'playwright';

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

(async () => {
    const browser = await chromium.launch({ headless: true });
    const page = await browser.newPage({ viewport: { width: 1280, height: 720 } });
    const errors = [];

    page.on('pageerror', (err) => {
        errors.push(`PAGE ERROR: ${err.message}`);
    });
    page.on('console', (msg) => {
        if (msg.type() === 'error') {
            errors.push(`CONSOLE ERROR: ${msg.text()}`);
        }
    });

    console.log('1. Loading app...');
    await page.goto('http://localhost:5174', { waitUntil: 'networkidle', timeout: 15000 });
    await sleep(2000);

    // Check if the Universe module loaded without import errors
    console.log('2. Checking for JS errors on load...');
    const loadErrors = errors.filter(e => !e.includes('favicon') && !e.includes('net::'));
    if (loadErrors.length > 0) {
        console.log('   ERRORS found on load:');
        loadErrors.forEach(e => console.log(`   - ${e}`));
    } else {
        console.log('   No JS errors on load.');
    }

    // Try to evaluate the hook's exported constant to verify it's importable
    console.log('3. Checking LABEL_Z_MAX export...');
    const labelZMax = await page.evaluate(async () => {
        try {
            // Dynamic import to check the module is valid
            const mod = await import('/src/components/Universe/hooks/useRocketMode.js');
            return { value: mod.LABEL_Z_MAX, hasDefault: typeof mod.default === 'function' };
        } catch (e) {
            return { error: e.message };
        }
    });
    console.log('   LABEL_Z_MAX:', JSON.stringify(labelZMax));

    // Navigate to Universe (hash route)
    console.log('4. Navigating to Universe...');
    await page.goto('http://localhost:5174/#/universe', { waitUntil: 'networkidle', timeout: 15000 });
    await sleep(3000);

    // Take a screenshot to see current state
    await page.screenshot({ path: 'test-rocket-universe.png' });
    console.log('   Screenshot saved: test-rocket-universe.png');

    // Check if there's an "Explore Galaxy" button or similar rocket entry point
    console.log('5. Looking for rocket mode entry...');
    const buttons = await page.$$eval('button', btns => btns.map(b => b.textContent.trim()).filter(t => t));
    console.log('   Buttons found:', buttons.slice(0, 10).join(', '));

    // Look for any explore/rocket button
    const exploreBtn = await page.$('button:has-text("Explore")');
    if (exploreBtn) {
        console.log('   Found Explore button, clicking...');
        await exploreBtn.click();
        await sleep(2000);
        await page.screenshot({ path: 'test-rocket-explore.png' });
        console.log('   Screenshot saved: test-rocket-explore.png');
    } else {
        console.log('   No Explore button visible (user might need to click a galaxy first)');
    }

    // Check for any rocket-mode related elements in DOM
    const rocketElements = await page.$$eval('[class*="rocket"]', els => els.map(e => e.className));
    console.log('6. Rocket-mode DOM elements:', rocketElements.length > 0 ? rocketElements : 'none yet');

    // Final error check
    console.log('\n=== Final Error Summary ===');
    const finalErrors = errors.filter(e => !e.includes('favicon') && !e.includes('net::ERR'));
    if (finalErrors.length > 0) {
        console.log('ERRORS:');
        finalErrors.forEach(e => console.log(`  - ${e}`));
    } else {
        console.log('No JS errors detected!');
    }

    await browser.close();
    process.exit(finalErrors.length > 0 ? 1 : 0);
})();

