/**
 * Unit test for the 3D rocket mode math — validates the core algorithms
 * without needing React or browser context.
 */

const PI = Math.PI;
const DEG = PI / 180;
const EPSILON = 0.001;

// ── Copy of key functions from useRocketMode.js ──
const getForwardVector = (yaw, pitch) => ({
    x: Math.sin(yaw) * Math.cos(pitch),
    y: Math.sin(pitch),
    z: Math.cos(yaw) * Math.cos(pitch),
});

const MIN_VIEW_Z = 0.5;

function viewTransform(star, cam, yaw, pitch) {
    const cosYaw = Math.cos(-yaw);
    const sinYaw = Math.sin(-yaw);
    const cosPitch = Math.cos(-pitch);
    const sinPitch = Math.sin(-pitch);

    const relX = star.worldX - cam.x;
    const relY = star.worldY - cam.y;
    const relZ = star.worldZ - cam.z;

    const rotX1 = relX * cosYaw + relZ * sinYaw;
    const rotZ1 = -relX * sinYaw + relZ * cosYaw;

    const rotY2 = relY * cosPitch - rotZ1 * sinPitch;
    const viewZ = relY * sinPitch + rotZ1 * cosPitch;

    return { _rotX1: rotX1, _rotY2: rotY2, viewZ };
}

function project(star, cx, cy, stageWidth) {
    if (star.viewZ <= MIN_VIEW_Z) return null;
    const focalLength = stageWidth * 0.6;
    return {
        projX: cx + (star._rotX1 / star.viewZ) * focalLength,
        projY: cy - (star._rotY2 / star.viewZ) * focalLength,
        scale: focalLength / star.viewZ,
    };
}

let pass = 0, fail = 0;

function assert(condition, msg) {
    if (condition) { pass++; console.log(`  PASS: ${msg}`); }
    else { fail++; console.log(`  FAIL: ${msg}`); }
}

function near(a, b, eps = EPSILON) { return Math.abs(a - b) < eps; }

// ── Test 1: Forward vector directions ──
console.log('\n=== Test 1: Forward Vector ===');
{
    const fwd0 = getForwardVector(0, 0);
    assert(near(fwd0.x, 0) && near(fwd0.y, 0) && near(fwd0.z, 1),
        'yaw=0, pitch=0 → forward along +Z');

    const fwd90 = getForwardVector(PI / 2, 0);
    assert(near(fwd90.x, 1) && near(fwd90.y, 0) && near(fwd90.z, 0),
        'yaw=90° → forward along +X');

    const fwdUp = getForwardVector(0, PI / 4);
    assert(near(fwdUp.y, Math.sin(PI / 4)) && fwdUp.z > 0,
        'pitch=45° up → positive Y component');

    const fwdDown = getForwardVector(0, -PI / 4);
    assert(near(fwdDown.y, -Math.sin(PI / 4)) && fwdDown.z > 0,
        'pitch=-45° → negative Y component');
}

// ── Test 2: View transform — star directly ahead ──
console.log('\n=== Test 2: View Transform ===');
{
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 0, worldY: 0, worldZ: 100 };
    const v = viewTransform(star, cam, 0, 0);
    assert(near(v.viewZ, 100), 'Star at (0,0,100) with cam at origin → viewZ=100');
    assert(near(v._rotX1, 0) && near(v._rotY2, 0), 'Centered in view');
}
{
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 0, worldY: 0, worldZ: -50 };
    const v = viewTransform(star, cam, 0, 0);
    assert(v.viewZ < MIN_VIEW_Z, 'Star behind camera → negative/low viewZ');
}
{
    // Star at +X with yaw=0 should appear to the right
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 50, worldY: 0, worldZ: 100 };
    const v = viewTransform(star, cam, 0, 0);
    assert(v._rotX1 > 0, 'Star to the right → positive _rotX1');
    assert(near(v._rotY2, 0, 0.1), 'Star at same height → _rotY2 near 0');
}
{
    // Star above with pitch=0 should appear above (positive _rotY2)
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 0, worldY: 50, worldZ: 100 };
    const v = viewTransform(star, cam, 0, 0);
    assert(v._rotY2 > 0, 'Star above → positive _rotY2');
}

// ── Test 3: Yaw rotation shifts stars ──
console.log('\n=== Test 3: Yaw Rotation ===');
{
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 100, worldY: 0, worldZ: 0 };
    // With yaw=90° (looking right/+X), this star should now be directly ahead
    const v = viewTransform(star, cam, PI / 2, 0);
    assert(v.viewZ > 50, 'Turning to face +X brings star into view (viewZ > 50)');
    assert(near(v._rotX1, 0, 1), 'Star centered horizontally after yaw');
}

// ── Test 4: Pitch rotation shifts stars ──
console.log('\n=== Test 4: Pitch Rotation ===');
{
    const cam = { x: 0, y: 0, z: 0 };
    const star = { worldX: 0, worldY: 100, worldZ: 0 };
    // With pitch=90° (looking straight up), star at y=100 should be ahead
    const v = viewTransform(star, cam, 0, PI / 2);
